diff --git a/llvm/lib/Transforms/Utils/LoopUtils.cpp b/llvm/lib/Transforms/Utils/LoopUtils.cpp
index f57d95e7722d..7c1505843a53 100644
--- a/llvm/lib/Transforms/Utils/LoopUtils.cpp
